import { useState, useCallback } from 'react'
import { Project } from '../../../stores/workspace.js'
import { DropTarget } from '../types.js'

interface UseDragAndDropOptions {
  projects: Project[]
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
  reorderCategories: (categoryIds: string[]) => void
  categories: Array<{ id: string; name: string; order: number; collapsed?: boolean }>
}

interface UseDragAndDropReturn {
  draggedProject: string | null
  draggedCategory: string | null
  dropTarget: DropTarget | null
  handleProjectDragStart: (e: React.DragEvent, projectPath: string) => void
  handleProjectDragEnd: () => void
  handleCategoryDragOver: (e: React.DragEvent, categoryId: string | null) => void
  handleCategoryDrop: (e: React.DragEvent, categoryId: string | null) => void
  handleProjectDragOver: (
    e: React.DragEvent,
    projectPath: string,
    position: 'before' | 'after'
  ) => void
  handleProjectDrop: (
    e: React.DragEvent,
    targetPath: string,
    targetCategoryId: string | undefined
  ) => void
  handleCategoryDragStart: (e: React.DragEvent, categoryId: string) => void
  handleCategoryDragEnd: () => void
  handleCategoryHeaderDragOver: (
    e: React.DragEvent,
    targetCategoryId: string,
    position: 'before' | 'after'
  ) => void
  handleCategoryHeaderDrop: (e: React.DragEvent, targetCategoryId: string) => void
}

export function useDragAndDrop({
  projects,
  moveProjectToCategory,
  reorderProjects,
  reorderCategories,
  categories,
}: UseDragAndDropOptions): UseDragAndDropReturn {
  const [draggedProject, setDraggedProject] = useState<string | null>(null)
  const [draggedCategory, setDraggedCategory] = useState<string | null>(null)
  const [dropTarget, setDropTarget] = useState<DropTarget | null>(null)

  const handleProjectDragStart = useCallback((e: React.DragEvent, projectPath: string) => {
    setDraggedProject(projectPath)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', projectPath)
    // Also set custom type so TiledTerminalView can detect sidebar project drags
    e.dataTransfer.setData('application/x-sidebar-project', projectPath)
  }, [])

  const handleProjectDragEnd = useCallback(() => {
    setDraggedProject(null)
    setDropTarget(null)
  }, [])

  const handleCategoryDragOver = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject) {
        setDropTarget({
          type: categoryId ? 'category' : 'uncategorized',
          id: categoryId,
        })
      }
    },
    [draggedProject]
  )

  const handleCategoryDrop = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      if (draggedProject) {
        moveProjectToCategory(draggedProject, categoryId)
      }
      setDraggedProject(null)
      setDropTarget(null)
    },
    [draggedProject, moveProjectToCategory]
  )

  const handleProjectDragOver = useCallback(
    (e: React.DragEvent, projectPath: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.stopPropagation()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject && draggedProject !== projectPath) {
        setDropTarget({ type: 'project', id: projectPath, position })
      }
    },
    [draggedProject]
  )

  const handleProjectDrop = useCallback(
    (e: React.DragEvent, targetPath: string, targetCategoryId: string | undefined) => {
      e.preventDefault()
      e.stopPropagation()

      if (draggedProject && draggedProject !== targetPath) {
        const draggedProjectData = projects.find((p) => p.path === draggedProject)
        const targetProject = projects.find((p) => p.path === targetPath)

        if (draggedProjectData && targetProject) {
          moveProjectToCategory(draggedProject, targetCategoryId ?? null)
          const categoryProjects = projects
            .filter((p) =>
              targetCategoryId ? p.categoryId === targetCategoryId : !p.categoryId
            )
            .sort((a, b) => (a.order ?? 0) - (b.order ?? 0))
            .map((p) => p.path)

          const newOrder = categoryProjects.filter((p) => p !== draggedProject)
          const targetIndex = newOrder.indexOf(targetPath)
          const insertIndex = dropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
          newOrder.splice(insertIndex, 0, draggedProject)
          reorderProjects(targetCategoryId ?? null, newOrder)
        }
      }
      setDraggedProject(null)
      setDropTarget(null)
    },
    [draggedProject, projects, dropTarget, moveProjectToCategory, reorderProjects]
  )

  const handleCategoryDragStart = useCallback((e: React.DragEvent, categoryId: string) => {
    setDraggedCategory(categoryId)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', categoryId)
  }, [])

  const handleCategoryDragEnd = useCallback(() => {
    setDraggedCategory(null)
    setDropTarget(null)
  }, [])

  const handleCategoryHeaderDragOver = useCallback(
    (e: React.DragEvent, targetCategoryId: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        setDropTarget({ type: 'category', id: targetCategoryId, position })
      }
    },
    [draggedCategory]
  )

  const handleCategoryHeaderDrop = useCallback(
    (e: React.DragEvent, targetCategoryId: string) => {
      e.preventDefault()
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        const orderedCategories = [...categories].sort((a, b) => a.order - b.order)
        const categoryIds = orderedCategories.map((c) => c.id)
        const newOrder = categoryIds.filter((id) => id !== draggedCategory)
        const targetIndex = newOrder.indexOf(targetCategoryId)
        const insertIndex = dropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
        newOrder.splice(insertIndex, 0, draggedCategory)
        reorderCategories(newOrder)
      }
      setDraggedCategory(null)
      setDropTarget(null)
    },
    [draggedCategory, categories, dropTarget, reorderCategories]
  )

  return {
    draggedProject,
    draggedCategory,
    dropTarget,
    handleProjectDragStart,
    handleProjectDragEnd,
    handleCategoryDragOver,
    handleCategoryDrop,
    handleProjectDragOver,
    handleProjectDrop,
    handleCategoryDragStart,
    handleCategoryDragEnd,
    handleCategoryHeaderDragOver,
    handleCategoryHeaderDrop,
  }
}

import React from 'react'
import { Project } from '../../stores/workspace.js'
import { ProjectIcon } from '../ProjectIcon.js'
import { ClaudeSession, DropTarget } from './types.js'
import { formatDate } from './utils.js'

interface ProjectItemProps {
  project: Project
  isExpanded: boolean
  isFocused: boolean
  hasOpenTab: boolean
  isDragging: boolean
  isEditing: boolean
  editingName: string
  sessions: ClaudeSession[]
  taskCounts?: { open: number; inProgress: number }
  dropTarget: DropTarget | null
  editInputRef: React.RefObject<HTMLInputElement | null>
  onToggleExpand: (e: React.MouseEvent) => void
  onOpenSession: (sessionId?: string, slug?: string, isNewSession?: boolean) => void
  onRunExecutable: () => void
  onCloseProjectTabs: () => void
  onContextMenu: (e: React.MouseEvent) => void
  onDragStart: (e: React.DragEvent) => void
  onDragEnd: () => void
  onDragOver: (e: React.DragEvent) => void
  onDrop: (e: React.DragEvent) => void
  onStartRename: (e: React.MouseEvent) => void
  onEditingChange: (name: string) => void
  onRenameSubmit: () => void
  onRenameKeyDown: (e: React.KeyboardEvent) => void
}

export const ProjectItem = React.memo(function ProjectItem({
  project,
  isExpanded,
  isFocused,
  hasOpenTab,
  isDragging,
  isEditing,
  editingName,
  sessions,
  taskCounts,
  dropTarget,
  editInputRef,
  onToggleExpand,
  onOpenSession,
  onRunExecutable,
  onCloseProjectTabs,
  onContextMenu,
  onDragStart,
  onDragEnd,
  onDragOver,
  onDrop,
  onStartRename,
  onEditingChange,
  onRenameSubmit,
  onRenameKeyDown,
}: ProjectItemProps) {
  const showDropBefore = dropTarget?.type === 'project' && dropTarget.id === project.path && dropTarget.position === 'before'
  const showDropAfter = dropTarget?.type === 'project' && dropTarget.id === project.path && dropTarget.position === 'after'

  return (
    <div>
      {showDropBefore && <div className="drop-indicator" />}

      <div
        className={`project-item ${isExpanded ? 'expanded' : ''} ${hasOpenTab ? 'has-open-tab' : ''} ${project.executable ? 'has-executable' : ''} ${project.color ? 'has-color' : ''} ${isFocused ? 'focused' : ''} ${isDragging ? 'dragging' : ''}`}
        style={project.color ? { backgroundColor: `${project.color}20` } : undefined}
        draggable={!isEditing}
        onDragStart={onDragStart}
        onDragEnd={onDragEnd}
        onDragOver={onDragOver}
        onDrop={onDrop}
        onClick={() => onOpenSession()}
        onContextMenu={onContextMenu}
      >
        <button
          className="expand-arrow"
          onClick={onToggleExpand}
          title="Show all sessions"
          aria-expanded={isExpanded}
          aria-label={`${isExpanded ? 'Collapse' : 'Expand'} sessions for ${project.name}`}
        >
          {isExpanded ? '▼' : '▶'}
        </button>
        <ProjectIcon projectName={project.name} size={28} />
        <div style={{ flex: 1, minWidth: 0 }}>
          {isEditing ? (
            <input
              ref={editInputRef}
              type="text"
              className="project-name-input"
              value={editingName}
              onChange={(e) => onEditingChange(e.target.value)}
              onKeyDown={onRenameKeyDown}
              onBlur={onRenameSubmit}
              onClick={(e) => e.stopPropagation()}
            />
          ) : (
            <div
              className="project-name"
              title={project.name}
              onDoubleClick={onStartRename}
            >
              {project.name}
            </div>
          )}
          {taskCounts ? (
            <div className="project-tasks" title={project.path}>
              {taskCounts.open + taskCounts.inProgress > 0 ? (
                <>
                  <span className="task-count">{taskCounts.open + taskCounts.inProgress} tasks</span>
                  {taskCounts.inProgress > 0 && (
                    <span className="task-in-progress">({taskCounts.inProgress} active)</span>
                  )}
                </>
              ) : (
                <span className="task-count task-done">No open tasks</span>
              )}
            </div>
          ) : (
            <div className="project-path" title={project.path}>{project.path}</div>
          )}
        </div>
        {project.executable && (
          <button
            className="start-btn"
            onClick={(e) => {
              e.stopPropagation()
              onRunExecutable()
            }}
            title={`Run: ${project.executable}`}
          >
            ▶
          </button>
        )}
        {hasOpenTab && (
          <button
            className="close-project-btn"
            onClick={(e) => {
              e.stopPropagation()
              onCloseProjectTabs()
            }}
            title="Close all terminals for this project"
          >
            ×
          </button>
        )}
      </div>

      {showDropAfter && <div className="drop-indicator" />}

      {isExpanded && (
        <div className="sessions-list">
          <div
            className="session-item new-session"
            onClick={(e) => {
              e.stopPropagation()
              onOpenSession(undefined, undefined, true)
            }}
          >
            <span>+</span>
            <span>New Session</span>
          </div>
          {sessions.map((session, index) => (
            <div
              key={session.sessionId}
              className={`session-item ${index === 0 ? 'most-recent' : ''}`}
              onClick={(e) => {
                e.stopPropagation()
                onOpenSession(session.sessionId, session.slug)
              }}
              title={`Session ID: ${session.sessionId}`}
            >
              <span className="session-icon">{index === 0 ? '●' : '◦'}</span>
              <span className="session-name" title={session.slug}>{session.slug}</span>
              <span className="session-time">{formatDate(session.lastModified)}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
})

import { Project } from '../../stores/workspace.js'

export function adjustMenuPosition(
  menu: HTMLElement,
  position: { x: number; y: number },
  padding = 8
): { x: number; y: number } {
  const rect = menu.getBoundingClientRect()
  let { x, y } = position

  if (rect.right > window.innerWidth - padding) {
    x = window.innerWidth - rect.width - padding
  }
  if (rect.bottom > window.innerHeight - padding) {
    y = window.innerHeight - rect.height - padding
  }

  return {
    x: Math.max(padding, x),
    y: Math.max(padding, y)
  }
}

export function getLuminance(hex: string): number {
  const r = parseInt(hex.slice(1, 3), 16) / 255
  const g = parseInt(hex.slice(3, 5), 16) / 255
  const b = parseInt(hex.slice(5, 7), 16) / 255

  const toLinear = (c: number) => c <= 0.03928 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4)

  return 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b)
}

export function getCategoryGradient(categoryProjects: Project[]): { background: string; textDark: boolean } {
  const colors = categoryProjects
    .map(p => p.color)
    .filter(Boolean) as string[]

  if (colors.length === 0) return { background: 'transparent', textDark: false }

  const avgLuminance = colors.reduce((sum, c) => sum + getLuminance(c), 0) / colors.length
  const textDark = avgLuminance > 0.4

  if (colors.length === 1) return { background: `${colors[0]}66`, textDark }

  const stops = colors.map((c, i) =>
    `${c}66 ${(i / (colors.length - 1)) * 100}%`
  ).join(', ')

  return { background: `linear-gradient(135deg, ${stops})`, textDark }
}

export function formatDate(timestamp: number): string {
  const diff = Date.now() - timestamp
  const minutes = Math.floor(diff / 60000)
  const hours = Math.floor(diff / 3600000)
  const days = Math.floor(diff / 86400000)

  if (minutes < 1) return 'Just now'
  if (minutes < 60) return `${minutes}m ago`
  if (hours < 24) return `${hours}h ago`
  if (days === 1) return 'Yesterday'
  if (days < 7) return `${days}d ago`
  return new Date(timestamp).toLocaleDateString()
}

import React from 'react'
import { ProjectCategory } from '../../stores/workspace.js'

interface CategoryHeaderProps {
  category: ProjectCategory
  projectCount: number
  gradient: string
  textDark: boolean
  isCollapsed: boolean
  isDragging: boolean
  isEditing: boolean
  editingName: string
  editInputRef: React.RefObject<HTMLInputElement | null>
  draggedCategory: string | null
  draggedProject: string | null
  onToggleCollapse: () => void
  onOpenAsProject: () => void
  onContextMenu: (e: React.MouseEvent) => void
  onDragStart: (e: React.DragEvent) => void
  onDragEnd: () => void
  onCategoryHeaderDragOver: (e: React.DragEvent, position: 'before' | 'after') => void
  onCategoryDragOver: (e: React.DragEvent) => void
  onCategoryHeaderDrop: (e: React.DragEvent) => void
  onCategoryDrop: (e: React.DragEvent) => void
  onStartRename: () => void
  onEditingChange: (name: string) => void
  onRenameSubmit: () => void
  onRenameKeyDown: (e: React.KeyboardEvent) => void
}

export const CategoryHeader = React.memo(function CategoryHeader({
  category,
  projectCount,
  gradient,
  textDark,
  isCollapsed,
  isDragging,
  isEditing,
  editingName,
  editInputRef,
  draggedCategory,
  draggedProject,
  onToggleCollapse,
  onOpenAsProject,
  onContextMenu,
  onDragStart,
  onDragEnd,
  onCategoryHeaderDragOver,
  onCategoryDragOver,
  onCategoryHeaderDrop,
  onCategoryDrop,
  onStartRename,
  onEditingChange,
  onRenameSubmit,
  onRenameKeyDown,
}: CategoryHeaderProps) {
  return (
    <div
      className={`category-header ${isCollapsed ? 'collapsed' : ''} ${isDragging ? 'dragging' : ''} ${textDark ? 'text-dark' : ''}`}
      style={{ background: gradient }}
      role="button"
      tabIndex={0}
      draggable={!isEditing}
      onDragStart={onDragStart}
      onDragEnd={onDragEnd}
      onDragOver={(e) => {
        const rect = e.currentTarget.getBoundingClientRect()
        const midY = rect.top + rect.height / 2
        const position = e.clientY < midY ? 'before' : 'after'
        if (draggedCategory) {
          onCategoryHeaderDragOver(e, position)
        } else if (draggedProject) {
          onCategoryDragOver(e)
        }
      }}
      onDrop={(e) => {
        if (draggedCategory) {
          onCategoryHeaderDrop(e)
        } else if (draggedProject) {
          onCategoryDrop(e)
        }
      }}
      onClick={onOpenAsProject}
      onKeyDown={(e) => {
        if (!isEditing && (e.key === 'Enter' || e.key === ' ')) {
          e.preventDefault()
          onOpenAsProject()
        }
      }}
      onContextMenu={onContextMenu}
      aria-expanded={!isCollapsed}
      aria-label={`${category.name} category`}
    >
      <span
        className="expand-arrow"
        aria-hidden="true"
        onClick={(e) => {
          e.stopPropagation()
          onToggleCollapse()
        }}
        role="button"
        tabIndex={0}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault()
            e.stopPropagation()
            onToggleCollapse()
          }
        }}
      >
        {isCollapsed ? '▶' : '▼'}
      </span>
      {isEditing ? (
        <input
          ref={editInputRef}
          type="text"
          className="category-name-input"
          value={editingName}
          onChange={(e) => onEditingChange(e.target.value)}
          onKeyDown={onRenameKeyDown}
          onBlur={onRenameSubmit}
          onClick={(e) => e.stopPropagation()}
        />
      ) : (
        <span className="category-name" onDoubleClick={onStartRename}>
          {category.name}
        </span>
      )}
      <span className="category-count">{projectCount}</span>
    </div>
  )
})

