import React from 'react'
import ReactDOM from 'react-dom'
import { ProjectSettingsModalState, InstalledVoice } from './types.js'
import { COMMON_TOOLS, PERMISSION_MODES, API_SESSION_MODES, API_MODELS } from './constants.js'

interface ProjectSettingsModalProps {
  state: ProjectSettingsModalState
  globalPermissions: { tools: string[]; mode: string }
  globalVoiceSettings: { voice: string; engine: string }
  installedVoices: InstalledVoice[]
  onClose: () => void
  onSave: () => void
  onChange: (updates: Partial<ProjectSettingsModalState>) => void
  onToggleTool: (tool: string) => void
  onAllowAll: () => void
  onClearAll: () => void
}

export function ProjectSettingsModal({
  state,
  globalPermissions,
  globalVoiceSettings,
  installedVoices,
  onClose,
  onSave,
  onChange,
  onToggleTool,
  onAllowAll,
  onClearAll,
}: ProjectSettingsModalProps) {
  const handleVoiceChange = (value: string) => {
    if (!value) {
      onChange({ ttsVoice: '', ttsEngine: '' })
    } else {
      const [engine, ...voiceParts] = value.split(':')
      const voice = voiceParts.join(':')
      onChange({ ttsVoice: voice, ttsEngine: engine as 'piper' | 'xtts' })
    }
  }

  return ReactDOM.createPortal(
    <div className="modal-overlay" onClick={() => !state.apiStatus && onClose()}>
      <div className="modal project-settings-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Project Settings: {state.project.name}</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-content">
          {/* API Settings Section */}
          <div className="settings-section">
            <h3>API Settings</h3>
            <p className="form-hint">Enable HTTP API to send prompts to this project's terminal.</p>

            <div className="form-group">
              <label>Port Number</label>
              <input
                type="number"
                min="1024"
                max="65535"
                value={state.apiPort}
                onChange={(e) => onChange({ apiPort: e.target.value, apiStatus: undefined, apiError: undefined })}
                placeholder="e.g., 3001 (leave empty to disable)"
                disabled={state.apiStatus === 'checking'}
                className={state.apiStatus === 'error' ? 'input-error' : ''}
              />
              {state.apiStatus === 'error' && (
                <p className="error-message">{state.apiError}</p>
              )}
            </div>

            <div className="form-group">
              <label className="checkbox-label">
                <input
                  type="checkbox"
                  checked={state.apiAutoStart}
                  onChange={(e) => onChange({ apiAutoStart: e.target.checked })}
                  disabled={!state.apiPort}
                />
                <span>Auto-start API on session open</span>
              </label>
              <p className="form-hint">When enabled, the API server starts automatically when you open a session for this project.</p>
            </div>

            <div className="form-group">
              <label>Session Mode</label>
              <p className="form-hint">How API requests handle terminal sessions.</p>
              <div className={`session-mode-options ${!state.apiPort ? 'disabled' : ''}`}>
                {API_SESSION_MODES.map((mode) => (
                  <label key={mode.value} className={`session-mode-option ${state.apiSessionMode === mode.value ? 'selected' : ''}`}>
                    <input
                      type="radio"
                      name="apiSessionMode"
                      value={mode.value}
                      checked={state.apiSessionMode === mode.value}
                      onChange={(e) => onChange({ apiSessionMode: e.target.value as 'existing' | 'new-keep' | 'new-close' })}
                      disabled={!state.apiPort}
                    />
                    <span className="mode-label">{mode.label}</span>
                    <span className="mode-desc">{mode.desc}</span>
                  </label>
                ))}
              </div>
            </div>

            {state.apiSessionMode !== 'existing' && (
              <div className="form-group">
                <label>API Session Model</label>
                <p className="form-hint">Model for API-triggered sessions. Use cheaper models for automated workflows.</p>
                <div className={`session-mode-options ${!state.apiPort ? 'disabled' : ''}`}>
                  {API_MODELS.map((model) => (
                    <label key={model.value} className={`session-mode-option ${state.apiModel === model.value ? 'selected' : ''}`}>
                      <input
                        type="radio"
                        name="apiModel"
                        value={model.value}
                        checked={state.apiModel === model.value}
                        onChange={(e) => onChange({ apiModel: e.target.value as 'default' | 'opus' | 'sonnet' | 'haiku' })}
                        disabled={!state.apiPort}
                      />
                      <span className="mode-label">{model.label}</span>
                      <span className="mode-desc">{model.desc}</span>
                    </label>
                  ))}
                </div>
              </div>
            )}

            {state.apiPort && (
              <p className="form-hint api-usage">
                Usage: <code>curl -X POST http://localhost:{state.apiPort}/prompt -d '{`{"prompt":"..."}`}'</code>
              </p>
            )}
          </div>

          {/* Permissions Section */}
          <div className="settings-section">
            <h3>Permissions</h3>
            <p className="form-hint">Override global permission settings for this project.</p>

            <div className="form-group">
              <label>Auto-Accept Tools</label>
              <div className="tool-chips">
                {COMMON_TOOLS.map((tool) => {
                  const isProjectSelected = state.tools.includes(tool.value)
                  const isGlobalSelected = globalPermissions.tools.includes(tool.value)
                  return (
                    <button
                      key={tool.value}
                      className={`tool-chip ${isProjectSelected ? 'selected' : ''} ${isGlobalSelected && !isProjectSelected ? 'global' : ''}`}
                      onClick={() => onToggleTool(tool.value)}
                      title={`${tool.value}${isGlobalSelected ? ' (enabled in global settings)' : ''}`}
                    >
                      {tool.label}
                      {isGlobalSelected && !isProjectSelected && <span className="global-indicator">G</span>}
                    </button>
                  )
                })}
              </div>
            </div>

            <div className="form-group">
              <label>Permission Mode</label>
              {globalPermissions.mode !== 'default' && state.permissionMode === 'default' && (
                <p className="form-hint global-hint">
                  Global: {PERMISSION_MODES.find(m => m.value === globalPermissions.mode)?.label}
                </p>
              )}
              <div className="permission-mode-options compact">
                {PERMISSION_MODES.map((mode) => {
                  const isGlobalMode = globalPermissions.mode === mode.value && state.permissionMode === 'default'
                  return (
                    <label key={mode.value} className={`permission-mode-option ${state.permissionMode === mode.value ? 'selected' : ''} ${isGlobalMode ? 'global' : ''}`}>
                      <input
                        type="radio"
                        name="permissionMode"
                        value={mode.value}
                        checked={state.permissionMode === mode.value}
                        onChange={(e) => onChange({ permissionMode: e.target.value })}
                      />
                      <span className="mode-label">{mode.label}</span>
                      <span className="mode-desc">{mode.desc}</span>
                      {isGlobalMode && <span className="global-indicator">G</span>}
                    </label>
                  )
                })}
              </div>
            </div>

            <div className="permission-quick-actions">
              <button className="btn-danger-outline" onClick={onAllowAll}>
                Allow All
              </button>
              <button className="btn-secondary" onClick={onClearAll}>
                Clear All
              </button>
            </div>
          </div>

          {/* Backend Settings Section */}
          <div className="settings-section">
            <h3>Backend Settings</h3>
            <p className="form-hint">Override the global default backend for this project.</p>

            <div className="form-group">
              <div className="permission-mode-options compact">
                {[
                  { value: 'default', label: 'Use global default', desc: 'Uses the backend selected in the main settings.' },
                  { value: 'claude', label: 'Claude', desc: 'Forces this project to use Claude.' },
                  { value: 'gemini', label: 'Gemini', desc: 'Forces this project to use Gemini.' },
                  { value: 'codex', label: 'Codex', desc: 'Forces this project to use Codex.' },
                  { value: 'opencode', label: 'OpenCode', desc: 'Forces this project to use OpenCode.' },
                  { value: 'aider', label: 'Aider', desc: 'Forces this project to use Aider.' },
                ].map((backend) => (
                  <label key={backend.value} className={`permission-mode-option ${state.backend === backend.value ? 'selected' : ''}`}>
                    <input
                      type="radio"
                      name="projectBackend"
                      value={backend.value}
                      checked={state.backend === backend.value}
                      onChange={(e) => onChange({ backend: e.target.value as typeof state.backend })}
                    />
                    <span className="mode-label">{backend.label}</span>
                    <span className="mode-desc">{backend.desc}</span>
                  </label>
                ))}
              </div>
            </div>
          </div>

          {/* Voice Settings Section */}
          <div className="settings-section">
            <h3>Voice</h3>
            <p className="form-hint">Override global TTS voice for this project.</p>

            <div className="form-group">
              <label>TTS Voice</label>
              {globalVoiceSettings.voice && !state.ttsVoice && (
                <p className="form-hint global-hint">
                  Global: {installedVoices.find(v => v.key === globalVoiceSettings.voice)?.displayName || globalVoiceSettings.voice}
                </p>
              )}
              <select
                className="voice-select"
                value={state.ttsVoice ? `${state.ttsEngine}:${state.ttsVoice}` : ''}
                onChange={(e) => handleVoiceChange(e.target.value)}
              >
                <option value="">Use global voice</option>
                {installedVoices.length > 0 && (
                  <>
                    {installedVoices.filter(v => v.source !== 'xtts').length > 0 && (
                      <optgroup label="Piper Voices">
                        {installedVoices
                          .filter(v => v.source !== 'xtts')
                          .map(v => (
                            <option key={v.key} value={`piper:${v.key}`}>
                              {v.displayName}
                              {v.key === globalVoiceSettings.voice && globalVoiceSettings.engine === 'piper' ? ' (global)' : ''}
                            </option>
                          ))}
                      </optgroup>
                    )}
                    {installedVoices.filter(v => v.source === 'xtts').length > 0 && (
                      <optgroup label="XTTS Cloned Voices">
                        {installedVoices
                          .filter(v => v.source === 'xtts')
                          .map(v => (
                            <option key={v.key} value={`xtts:${v.key}`}>
                              {v.displayName}
                              {v.key === globalVoiceSettings.voice && globalVoiceSettings.engine === 'xtts' ? ' (global)' : ''}
                            </option>
                          ))}
                      </optgroup>
                    )}
                  </>
                )}
              </select>
              {installedVoices.length === 0 && (
                <p className="form-hint">No voices installed. Install voices in Settings.</p>
              )}
            </div>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-secondary" onClick={onClose} disabled={state.apiStatus === 'checking'}>Cancel</button>
          <button className="btn-primary" onClick={onSave} disabled={state.apiStatus === 'checking'}>
            {state.apiStatus === 'checking' ? 'Checking...' : 'Save'}
          </button>
        </div>
      </div>
    </div>,
    document.body
  )
}

import { useState, useEffect, useCallback, useRef } from 'react'
import { Project } from '../../../stores/workspace.js'
import { OpenTab, ClaudeSession } from '../types.js'
import type { BackendId } from '../../../api/types'

interface UseSessionsOptions {
  projects: Project[]
  openTabs: OpenTab[]
  onOpenSession: (
    projectPath: string,
    sessionId?: string,
    slug?: string,
    initialPrompt?: string,
    forceNewSession?: boolean
  ) => void
  onSwitchToTab: (tabId: string) => void
}

interface UseSessionsReturn {
  expandedProject: string | null
  setExpandedProject: React.Dispatch<React.SetStateAction<string | null>>
  sessions: Record<string, ClaudeSession[]>
  toggleProject: (e: React.MouseEvent, path: string) => void
  openMostRecentSession: (projectPath: string) => Promise<void>
  handleOpenSession: (
    projectPath: string,
    sessionId?: string,
    slug?: string,
    isNewSession?: boolean
  ) => void
}

export function useSessions({
  projects,
  openTabs,
  onOpenSession,
  onSwitchToTab,
}: UseSessionsOptions): UseSessionsReturn {
  const [expandedProject, setExpandedProject] = useState<string | null>(null)
  const [sessions, setSessions] = useState<Record<string, ClaudeSession[]>>({})

  // Load sessions when a project is expanded
  useEffect(() => {
    async function loadSessions(): Promise<void> {
      if (expandedProject) {
        try {
          const project = projects.find((item) => item.path === expandedProject)
          const backend = ((project?.backend && project.backend !== 'default')
            ? project.backend
            : 'claude') as BackendId
          const projectSessions = (await window.electronAPI?.discoverSessions(
            expandedProject,
            backend
          )) as ClaudeSession[] | undefined
          setSessions((prev) => ({ ...prev, [expandedProject]: projectSessions ?? [] }))
        } catch (e) {
          console.error('Failed to discover sessions:', e)
        }
      }
    }
    loadSessions()
  }, [expandedProject, projects])

  const toggleProject = useCallback((e: React.MouseEvent, path: string) => {
    e.stopPropagation()
    setExpandedProject((prev) => (prev === path ? null : path))
  }, [])

  const openMostRecentSession = useCallback(
    async (projectPath: string) => {
      const existingTab = openTabs.find((tab) => tab.projectPath === projectPath)
      const project = projects.find((item) => item.path === projectPath)
      const effectiveBackend =
        project?.backend && project.backend !== 'default' ? project.backend : 'claude'

      if (existingTab) {
        onSwitchToTab(existingTab.id)
        return
      }

      const backend = (effectiveBackend || 'claude') as BackendId
      let projectSessions = sessions[projectPath]

      if (!projectSessions) {
        try {
          projectSessions = ((await window.electronAPI?.discoverSessions(projectPath, backend)) as ClaudeSession[] | undefined) ?? []
          setSessions((prev) => ({ ...prev, [projectPath]: projectSessions! }))
        } catch (e) {
          console.error('Failed to discover sessions:', e)
          projectSessions = []
        }
      }

      if (projectSessions.length > 0) {
        const mostRecent = projectSessions[0]
        onOpenSession(projectPath, mostRecent.sessionId, mostRecent.slug)
      } else {
        onOpenSession(projectPath, undefined, undefined, undefined, false)
      }
    },
    [openTabs, projects, sessions, onSwitchToTab, onOpenSession]
  )

  const handleOpenSession = useCallback(
    (projectPath: string, sessionId?: string, slug?: string, isNewSession?: boolean) => {
      if (sessionId) {
        onOpenSession(projectPath, sessionId, slug)
      } else if (isNewSession) {
        // Explicit "New Session" click - always create a new session
        onOpenSession(projectPath, undefined, undefined, undefined, true)
      } else {
        openMostRecentSession(projectPath)
      }
    },
    [onOpenSession, openMostRecentSession]
  )

  return {
    expandedProject,
    setExpandedProject,
    sessions,
    toggleProject,
    openMostRecentSession,
    handleOpenSession,
  }
}

import { useCallback } from 'react'
import { Project, useWorkspaceStore } from '../../stores/workspace.js'
import { SidebarState } from './useSidebarState.js'
import { SidebarProps } from './types.js'

// Use type assertion for extended electronAPI methods not in the base type
const electronAPI = window.electronAPI as (typeof window.electronAPI) & {
  selectExecutable?: () => Promise<string | null>
  runExecutable?: (executable: string, cwd: string) => Promise<{ success: boolean; error?: string }>
  getCategoryMetaPath?: (categoryName: string) => Promise<string>
  getMetaProjectsPath?: () => Promise<string>
}

export interface SidebarHandlers {
  // Project handlers
  handleSelectExecutable: (project: Project) => Promise<void>
  handleClearExecutable: (project: Project) => void
  handleRunExecutable: (project: Project) => Promise<void>

  // Rename handlers
  handleStartRename: (e: React.MouseEvent, project: Project) => void
  handleRenameSubmit: () => void
  handleRenameKeyDown: (e: React.KeyboardEvent) => void

  // Category handlers
  handleAddCategory: () => void
  handleOpenCategoryAsProject: (categoryName: string) => Promise<void>
  handleOpenAllProjects: () => Promise<void>
  handleStartCategoryRename: (
    category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]
  ) => void
  handleCategoryRenameSubmit: () => void
  handleCategoryRenameKeyDown: (e: React.KeyboardEvent) => void
  toggleCategoryCollapse: (categoryId: string) => void

  // Resize handler
  handleMouseDown: (e: React.MouseEvent) => void

  // Backdrop handler
  handleBackdropClick: () => void
}

export interface UseSidebarHandlersParams {
  state: SidebarState
  onUpdateProject: SidebarProps['onUpdateProject']
  onOpenSession: SidebarProps['onOpenSession']
  isMobile: boolean
  onMobileClose: (() => void) | undefined
}

export function useSidebarHandlers(params: UseSidebarHandlersParams): SidebarHandlers {
  const { state, onUpdateProject, onOpenSession, isMobile, onMobileClose } = params
  const {
    setContextMenu,
    editingProject,
    setEditingProject,
    editInputRef,
    editingCategory,
    setEditingCategory,
    categoryEditInputRef,
    addCategory,
    updateCategory,
    categories,
    setIsResizing,
    moveProjectToCategory,
  } = state

  // Project handlers
  const handleSelectExecutable = useCallback(
    async (project: Project) => {
      const executable = await electronAPI?.selectExecutable?.()
      if (executable) onUpdateProject(project.path, { executable })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleClearExecutable = useCallback(
    (project: Project) => {
      onUpdateProject(project.path, { executable: undefined })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleRunExecutable = useCallback(
    async (project: Project) => {
      if (project.executable) {
        const result = await electronAPI?.runExecutable?.(project.executable, project.path)
        if (result && !result.success) console.error('Failed to run executable:', result.error)
      }
      setContextMenu(null)
    },
    [setContextMenu]
  )

  // Rename handlers
  const handleStartRename = useCallback(
    (e: React.MouseEvent, project: Project) => {
      e.stopPropagation()
      setEditingProject({ path: project.path, name: project.name })
      setTimeout(() => editInputRef.current?.select(), 0)
    },
    [setEditingProject, editInputRef]
  )

  const handleRenameSubmit = useCallback(() => {
    if (editingProject && editingProject.name.trim()) {
      onUpdateProject(editingProject.path, { name: editingProject.name.trim() })
    }
    setEditingProject(null)
  }, [editingProject, onUpdateProject, setEditingProject])

  const handleRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleRenameSubmit()
      else if (e.key === 'Escape') setEditingProject(null)
    },
    [handleRenameSubmit, setEditingProject]
  )

  // Category handlers
  const handleAddCategory = useCallback(() => {
    const newId = addCategory('New Category')
    setEditingCategory({ id: newId, name: 'New Category' })
    setTimeout(() => categoryEditInputRef.current?.select(), 0)
  }, [addCategory, setEditingCategory, categoryEditInputRef])

  const handleOpenCategoryAsProject = useCallback(
    async (categoryName: string) => {
      const metaPath = await electronAPI?.getCategoryMetaPath?.(categoryName)
      if (metaPath) onOpenSession(metaPath)
    },
    [onOpenSession]
  )

  const handleOpenAllProjects = useCallback(async () => {
    const metaPath = await electronAPI?.getMetaProjectsPath?.()
    if (metaPath) onOpenSession(metaPath)
  }, [onOpenSession])

  const handleStartCategoryRename = useCallback(
    (category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]) => {
      setEditingCategory({ id: category.id, name: category.name })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [setEditingCategory, categoryEditInputRef]
  )

  const handleCategoryRenameSubmit = useCallback(() => {
    if (editingCategory && editingCategory.name.trim()) {
      updateCategory(editingCategory.id, { name: editingCategory.name.trim() })
    }
    setEditingCategory(null)
  }, [editingCategory, updateCategory, setEditingCategory])

  const handleCategoryRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleCategoryRenameSubmit()
      else if (e.key === 'Escape') setEditingCategory(null)
    },
    [handleCategoryRenameSubmit, setEditingCategory]
  )

  const toggleCategoryCollapse = useCallback(
    (categoryId: string) => {
      const category = categories.find((c) => c.id === categoryId)
      if (category) updateCategory(categoryId, { collapsed: !category.collapsed })
    },
    [categories, updateCategory]
  )

  // Resize handler
  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault()
      setIsResizing(true)
    },
    [setIsResizing]
  )

  // Backdrop handler
  const handleBackdropClick = useCallback(() => {
    if (isMobile && onMobileClose) {
      onMobileClose()
    }
  }, [isMobile, onMobileClose])

  return {
    handleSelectExecutable,
    handleClearExecutable,
    handleRunExecutable,
    handleStartRename,
    handleRenameSubmit,
    handleRenameKeyDown,
    handleAddCategory,
    handleOpenCategoryAsProject,
    handleOpenAllProjects,
    handleStartCategoryRename,
    handleCategoryRenameSubmit,
    handleCategoryRenameKeyDown,
    toggleCategoryCollapse,
    handleMouseDown,
    handleBackdropClick,
  }
}

// Helper for creating category with project
export function useCreateCategoryWithProject(
  state: SidebarState
): (projectPath: string) => void {
  const { addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef } = state

  return useCallback(
    (projectPath: string) => {
      const newId = addCategory('New Category')
      moveProjectToCategory(projectPath, newId)
      setContextMenu(null)
      setEditingCategory({ id: newId, name: 'New Category' })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef]
  )
}

import React, { useRef, useLayoutEffect } from 'react'
import ReactDOM from 'react-dom'
import { Project, ProjectCategory } from '../../stores/workspace.js'
import { adjustMenuPosition } from './utils.js'
import { PROJECT_COLORS } from './constants.js'

interface ProjectContextMenuProps {
  x: number
  y: number
  project: Project
  categories: ProjectCategory[]
  onClose: () => void
  onRunExecutable: () => void
  onSelectExecutable: () => void
  onClearExecutable: () => void
  onOpenSettings: () => void
  onOpenExtensions: () => void
  onEditClaudeMd: () => void
  onUpdateColor: (color: string | undefined) => void
  onMoveToCategory: (categoryId: string | null) => void
  onCreateCategory: () => void
  onDelete: () => void
}

export function ProjectContextMenu({
  x,
  y,
  project,
  categories,
  onClose,
  onRunExecutable,
  onSelectExecutable,
  onClearExecutable,
  onOpenSettings,
  onOpenExtensions,
  onEditClaudeMd,
  onUpdateColor,
  onMoveToCategory,
  onCreateCategory,
  onDelete,
}: ProjectContextMenuProps) {
  const menuRef = useRef<HTMLDivElement>(null)

  useLayoutEffect(() => {
    if (menuRef.current) {
      const adjusted = adjustMenuPosition(menuRef.current, { x, y })
      if (adjusted.x !== x || adjusted.y !== y) {
        menuRef.current.style.left = `${adjusted.x}px`
        menuRef.current.style.top = `${adjusted.y}px`
      }
    }
  }, [x, y])

  const sortedCategories = [...categories].sort((a, b) => a.order - b.order)

  return ReactDOM.createPortal(
    <div
      ref={menuRef}
      className="context-menu"
      style={{ left: x, top: y }}
      onClick={(e) => e.stopPropagation()}
    >
      {project.executable ? (
        <>
          <button onClick={onRunExecutable}>
            <span className="icon">▶</span> Run App
          </button>
          <button onClick={onSelectExecutable}>
            <span className="icon">⚡</span> Change Executable
          </button>
          <button onClick={onClearExecutable}>
            <span className="icon">✕</span> Clear Executable
          </button>
        </>
      ) : (
        <button onClick={onSelectExecutable}>
          <span className="icon">⚡</span> Set Executable
        </button>
      )}
      <div className="context-menu-divider" />
      <button onClick={onOpenSettings}>
        <span className="icon">⚙</span> Project Settings
        {(project.apiPort || project.autoAcceptTools?.length || project.permissionMode) && (
          <span className="menu-hint">configured</span>
        )}
      </button>
      <button onClick={onOpenExtensions}>
        <span className="icon">🧩</span> Extensions...
      </button>
      <button onClick={onEditClaudeMd}>
        <span className="icon">📝</span> Edit CLAUDE.md
      </button>
      <div className="context-menu-divider" />
      <div className="context-menu-label">Color</div>
      <div className="color-picker-row">
        {PROJECT_COLORS.map((color) => (
          <button
            key={color.name}
            className={`color-swatch ${project.color === color.value ? 'selected' : ''} ${!color.value ? 'none' : ''}`}
            style={color.value ? { backgroundColor: color.value } : undefined}
            title={color.name}
            onClick={() => {
              onUpdateColor(color.value)
              onClose()
            }}
          >
            {!color.value && '✕'}
          </button>
        ))}
      </div>
      <div className="context-menu-divider" />
      <div className="context-menu-label">Move to Category</div>
      <div className="category-move-options">
        <button
          className={!project.categoryId ? 'selected' : ''}
          onClick={() => {
            onMoveToCategory(null)
            onClose()
          }}
        >
          <span className="icon">—</span> None
        </button>
        {sortedCategories.map((cat) => (
          <button
            key={cat.id}
            className={project.categoryId === cat.id ? 'selected' : ''}
            onClick={() => {
              onMoveToCategory(cat.id)
              onClose()
            }}
          >
            <span className="icon">📁</span> {cat.name}
          </button>
        ))}
        <button onClick={onCreateCategory}>
          <span className="icon">+</span> New Category
        </button>
      </div>
      <div className="context-menu-divider" />
      <button className="danger" onClick={onDelete}>
        <span className="icon">🗑</span> Remove Project
      </button>
    </div>,
    document.body
  )
}

