    62→    const handleMouseUp = () => setIsResizing(false)
    63→
    64→    if (isResizing) {
    65→      document.addEventListener('mousemove', handleMouseMove)
    66→      document.addEventListener('mouseup', handleMouseUp)
    67→      document.body.style.cursor = 'ew-resize'
    68→      document.body.style.userSelect = 'none'
    69→    }
    70→
    71→    return () => {
    72→      if (rafId !== null) cancelAnimationFrame(rafId)
    73→      document.removeEventListener('mousemove', handleMouseMove)
    74→      document.removeEventListener('mouseup', handleMouseUp)
    75→      document.body.style.cursor = ''
    76→      document.body.style.userSelect = ''
    77→    }
    78→  }, [isResizing, onWidthChange, setIsResizing])
    79→
    80→  // Close context menus on click
    81→  useEffect(() => {
    82→    const handleClick = () => {
    83→      setContextMenu(null)
    84→      setCategoryContextMenu(null)
    85→    }
    86→    if (contextMenu || categoryContextMenu) {
    87→      document.addEventListener('click', handleClick)
    88→      return () => document.removeEventListener('click', handleClick)
    89→    }
    90→  }, [contextMenu, categoryContextMenu, setContextMenu, setCategoryContextMenu])
    91→
    92→  // Fetch API status when context menu opens
    93→  useEffect(() => {
    94→    if (contextMenu && electronAPI?.apiStatus) {
    95→      electronAPI.apiStatus(contextMenu.project.path).then((status) => {
    96→        setApiStatus((prev) => ({ ...prev, [contextMenu.project.path]: status }))
    97→      })
    98→    }
    99→  }, [contextMenu, setApiStatus])
   100→
   101→  // Fetch task counts for all projects
   102→  useEffect(() => {
   103→    async function fetchTaskCounts(): Promise<void> {
   104→      if (!electronAPI?.beadsCheck) return
   105→      const counts: Record<string, { open: number; inProgress: number }> = {}
   106→      for (const project of projects) {
   107→        try {
   108→          const status = await electronAPI.beadsCheck(project.path)
   109→          if (status.installed && status.initialized && electronAPI.beadsList) {
   110→            const result = await electronAPI.beadsList(project.path)
   111→            if (result.success && result.tasks) {
   112→              const tasks = result.tasks as Array<{ status: string }>
   113→              const open = tasks.filter((t) => t.status === 'open').length
   114→              const inProgress = tasks.filter((t) => t.status === 'in_progress').length
   115→              counts[project.path] = { open, inProgress }
   116→            }
   117→          }
   118→        } catch {
   119→          /* ignore */
   120→        }
   121→      }
   122→      setTaskCounts(counts)
   123→    }
   124→    fetchTaskCounts()
   125→    const interval = setInterval(fetchTaskCounts, 30000)
   126→    return () => clearInterval(interval)
   127→  }, [projects, setTaskCounts])
   128→
   129→  // Fetch API status for focused project
   130→  useEffect(() => {
   131→    if (focusedProjectPath && electronAPI?.apiStatus) {
   132→      electronAPI.apiStatus(focusedProjectPath).then((status) => {
   133→        setApiStatus((prev) => ({ ...prev, [focusedProjectPath]: status }))
   134→      })
   135→    }
   136→  }, [focusedProjectPath, setApiStatus])
   137→
   138→  // Check debug mode on mount
   139→  useEffect(() => {
   140→    electronAPI?.isDebugMode?.()?.then(setIsDebugMode)
   141→  }, [setIsDebugMode])
   142→
   143→  // Export handleMouseDown for use in the component
   144→  return
   145→}
   146→
   147→export function useResizeHandler(
   148→  setIsResizing: (v: boolean) => void
   149→): (e: React.MouseEvent) => void {
   150→  return useCallback(
   151→    (e: React.MouseEvent) => {
   152→      e.preventDefault()
   153→      setIsResizing(true)
   154→    },
   155→    [setIsResizing]
   156→  )
   157→}
